    }

    function repeat(ch, n) {
        var s = '';
        for (var i = 0; i < n; i++) { s += ch; }
        return s;
    }

    return {
        completeRandomization: completeRandomization,
        rcbd: rcbd,
        latinSquare: latinSquare,
        renderSchedule: renderSchedule,
        toCSV: toCSV,
        toJSON: toJSON
    };
}

