                    lines.push(padRight(String(asn.unit), 8) + padRight(String(asn.position), 6) + treatLabel);
                }
                lines.push('');
            }
        }

        if (design.type === 'CompleteRandomization') {
            lines.push('── Assignment Order ──');
            lines.push(padRight('Unit', 8) + 'Treatment');
            lines.push(repeat('─', 25));
